import React, { ReactNode, useState, useRef, useEffect, DragEvent } from 'react';
import { X, Check, AlertCircle, ChevronDown, Search, ChevronLeft, ChevronRight, ArrowUp, ArrowDown, Plus, Trash2, ArrowUpDown, GripVertical, Loader2 } from 'lucide-react';

// --- Utility: Classes ---
const cn = (...classes: (string | undefined | null | false)[]) => classes.filter(Boolean).join(' ');

// --- Button ---
interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ variant = 'primary', size = 'md', icon, children, className, ...props }) => {
  const baseStyle = "inline-flex items-center justify-center rounded transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed font-medium";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white focus:ring-blue-500 shadow-sm",
    secondary: "bg-slate-800 hover:bg-slate-700 text-slate-200 focus:ring-slate-500 border border-slate-600",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-300 hover:text-white"
  };

  const sizes = {
    sm: "px-2 py-1 text-xs",
    md: "px-4 py-1.5 text-sm",
    lg: "px-6 py-3 text-base"
  };

  return (
    <button className={cn(baseStyle, variants[variant], sizes[size], className)} {...props}>
      {icon && <span className={children ? "mr-2" : ""}>{icon}</span>}
      {children}
    </button>
  );
};

// --- Switch ---
export const Switch: React.FC<{ checked: boolean; onChange: (checked: boolean) => void; disabled?: boolean }> = ({ checked, onChange, disabled }) => {
  return (
    <button 
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      className={cn(
        "relative inline-flex h-5 w-9 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900",
        checked ? "bg-blue-600" : "bg-slate-700",
        disabled && "opacity-50 cursor-not-allowed"
      )}
    >
      <span
        className={cn(
          "inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform",
          checked ? "translate-x-4.5" : "translate-x-1"
        )}
        style={{ transform: checked ? 'translateX(18px)' : 'translateX(2px)' }}
      />
    </button>
  );
};

// --- Badge ---
export const Badge: React.FC<{ color?: 'blue' | 'green' | 'red' | 'yellow' | 'gray' | 'purple'; children: ReactNode; className?: string }> = ({ color = 'blue', children, className }) => {
  const colors = {
    blue: "bg-blue-900/30 text-blue-400 border-blue-800",
    green: "bg-emerald-900/30 text-emerald-400 border-emerald-800",
    red: "bg-red-900/30 text-red-400 border-red-800",
    yellow: "bg-amber-900/30 text-amber-400 border-amber-800",
    gray: "bg-slate-800 text-slate-400 border-slate-700",
    purple: "bg-purple-900/30 text-purple-400 border-purple-800"
  };

  return (
    <span className={cn("inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium border", colors[color], className)}>
      {children}
    </span>
  );
};

// --- Input ---
interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  prefix?: ReactNode;
}

export const Input: React.FC<InputProps> = ({ label, prefix, className, ...props }) => {
  return (
    <div className={className}>
      {label && <label className="block text-xs text-slate-400 mb-1.5">{label}</label>}
      <div className="relative">
        {prefix && (
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
            {prefix}
          </div>
        )}
        <input 
          className={cn(
            "block w-full rounded border border-slate-700 bg-[#1e293b] text-slate-200 shadow-sm focus:border-blue-500 focus:ring-1 focus:ring-blue-500 sm:text-sm placeholder-slate-600 transition-colors",
            prefix ? "pl-9" : "pl-3",
            "py-1.5"
          )}
          {...props}
        />
      </div>
    </div>
  );
};

// --- Select ---
interface SelectProps extends React.SelectHTMLAttributes<HTMLSelectElement> {
  label?: string;
  options: { label: string; value: string }[];
}

export const Select: React.FC<SelectProps> = ({ label, options, className, ...props }) => {
  return (
