// --- Column Configuration Dialog (With Drag & Drop) ---
export const ColumnConfigDialog: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  allColumns: { key: string; header: string }[];
  currentOrder: string[];
  onSave: (newOrder: string[]) => void;
}> = ({ isOpen, onClose, allColumns, currentOrder, onSave }) => {

    // State to hold the local list of columns (both Visible and Hidden, ordered)
    const [items, setItems] = useState<{ key: string; header: string; visible: boolean }[]>([]);
    const [draggingIndex, setDraggingIndex] = useState<number | null>(null);

    useEffect(() => {
        if (isOpen) {
            // 1. Map existing visible columns first, in their order
            const visibleItems = currentOrder.map(key => {
                const col = allColumns.find(c => c.key === key);
                return col ? { ...col, visible: true } : null;
            }).filter(Boolean) as { key: string; header: string; visible: boolean }[];

            // 2. Map hidden columns (those in allColumns but not in currentOrder)
            const hiddenItems = allColumns
                .filter(c => !currentOrder.includes(c.key))
                .map(c => ({ ...c, visible: false }));

            setItems([...visibleItems, ...hiddenItems]);
        }
    }, [isOpen, allColumns, currentOrder]);

    const handleDragStart = (e: DragEvent<HTMLDivElement>, index: number) => {
        setDraggingIndex(index);
        e.dataTransfer.effectAllowed = "move";
        // Ghost image transparency set by browser usually, or we can customize
    };

    const handleDragOver = (e: DragEvent<HTMLDivElement>, index: number) => {
        e.preventDefault(); // Necessary to allow dropping
        if (draggingIndex === null || draggingIndex === index) return;

        // Reorder list
        const newItems = [...items];
        const draggedItem = newItems[draggingIndex];
        newItems.splice(draggingIndex, 1);
        newItems.splice(index, 0, draggedItem);

        setItems(newItems);
        setDraggingIndex(index);
    };

    const handleDrop = (e: DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setDraggingIndex(null);
    };

    const toggleVisibility = (index: number) => {
        const newItems = [...items];
        newItems[index].visible = !newItems[index].visible;
        setItems(newItems);
    };

    const handleSaveLocal = () => {
        // Extract keys of visible items in their current order
        const newOrder = items.filter(i => i.visible).map(i => i.key);
        onSave(newOrder);
        onClose();
    };

    return (
        <Modal 
            isOpen={isOpen} 
            onClose={onClose} 
            title="列配置" 
            size="sm"
            footer={
                <>
                    <Button variant="secondary" onClick={() => {
                        // Reset to default (all columns, default order)
                        setItems(allColumns.map(c => ({...c, visible: true})));
                    }}>重置默认</Button>
                    <div className="flex-1"></div>
                    <Button variant="secondary" onClick={onClose}>取消</Button>
                    <Button onClick={handleSaveLocal}>保存</Button>
                </>
            }
        >
            <div className="space-y-1 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                <div className="text-xs text-slate-500 mb-2 flex justify-between px-2">
                    <span>显示 / 排序</span>
                    <span>拖动图标排序</span>
                </div>
                {items.map((item, index) => (
                    <div 
                        key={item.key}
                        draggable
                        onDragStart={(e) => handleDragStart(e, index)}
                        onDragOver={(e) => handleDragOver(e, index)}
                        onDrop={handleDrop}
                        className={cn(
                            "flex items-center justify-between p-2 rounded border border-transparent hover:bg-slate-800 transition-colors group cursor-move",
                            draggingIndex === index ? "bg-slate-800 border-blue-500/50 opacity-50" : "bg-[#0f172a] border-slate-700"
                        )}
                    >
                        <div className="flex items-center gap-3">
                            <GripVertical size={16} className="text-slate-600 group-hover:text-slate-400 cursor-grab active:cursor-grabbing" />
                            <label className="flex items-center gap-2 cursor-pointer select-none">
                                <input 
                                    type="checkbox" 
                                    checked={item.visible} 
                                    onChange={() => toggleVisibility(index)}
                                    className="rounded bg-slate-800 border-slate-600 text-blue-500 focus:ring-offset-slate-900"
                                />
                                <span className={cn("text-sm", item.visible ? "text-slate-200" : "text-slate-500")}>
                                    {item.header}
                                </span>
                            </label>
                        </div>
                        {item.visible && <div className="w-2 h-2 rounded-full bg-blue-500/30"></div>}
                    </div>
                ))}
            </div>
        </Modal>
    );
};

